 1	import * as _ from 'lodash-es';
 2	import * as React from 'react';
 3	import * as PropTypes from 'prop-types';
 4	import { Alert, AlertGroup, Panel, PanelMain, PanelMainBody } from '@patternfly/react-core';
 5	import { useTranslation } from 'react-i18next';
 6	import { LoadingInline } from '../console-shared/src/components/loading/LoadingInline';
 7	
 8	const injectDisabled = (children, disabled) => {
 9	  return React.Children.map(children, (c) => {
10	    if (!_.isObject(c) || c.type !== 'button') {
11	      return c;
12	    }
13	
14	    return React.cloneElement(c, { disabled: c.props.disabled || disabled });
15	  });
16	};
17	
18	const ErrorMessage = ({ message }) => {
19	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
20	  return (
21	    <Alert isInline variant="danger" title={t('public~An error occurred')} data-test="alert-error">
22	      <Panel isScrollable>
23	        <PanelMain maxHeight="100px">
24	          <PanelMainBody className="pf-v6-u-text-break-word monitoring__pre-line">
25	            {message}
26	          </PanelMainBody>
27	        </PanelMain>
28	      </Panel>
29	    </Alert>
30	  );
31	};
32	const InfoMessage = ({ message }) => (
33	  <Alert isInline variant="info" title={message} data-test="button-bar-info-message" />
34	);
35	const SuccessMessage = ({ message }) => <Alert isInline variant="success" title={message} />;
36	
37	export const ButtonBar = ({
38	  children,
39	  className,
40	  errorMessage,
41	  infoMessage,
42	  successMessage,
43	  inProgress,
44	}) => {
45	  return (
46	    <div className={className}>
47	      <AlertGroup
48	        isLiveRegion
49	        aria-live="polite"
50	        aria-atomic="false"
51	        aria-relevant="additions text"
52	      >
53	        {successMessage && <SuccessMessage message={successMessage} />}
54	        {errorMessage && <ErrorMessage message={errorMessage} />}
55	        {injectDisabled(children, inProgress)}
56	        {inProgress && <LoadingInline />}
57	        {infoMessage && <InfoMessage message={infoMessage} />}
58	      </AlertGroup>
59	    </div>
60	  );
61	};
62	
63	ButtonBar.propTypes = {
64	  children: PropTypes.node.isRequired,
65	  successMessage: PropTypes.string,
66	  errorMessage: PropTypes.node,
67	  infoMessage: PropTypes.string,
68	  inProgress: PropTypes.bool,
69	  className: PropTypes.string,
70	};

